TITLE = '外食費・食費最適化診断 | 外食バランスと節約プランを無料チェック'
DESCRIPTION = '外食頻度・家族構成・食費予算から最適な外食バランスと節約プランを診断。外食費が多すぎるか適切か判定し、年間節約額を試算します。'
JS_CODE = 'const QUESTIONS = [\n  {id:\'budget\', q:\'Q1. 月の食費予算（外食含む全体）はどのくらいですか？\', opts:[\'2万円未満\',\'2〜3万円\',\'3〜5万円\',\'5〜8万円\',\'8〜12万円\',\'12万円以上\']},\n  {id:\'frequency\', q:\'Q2. 週に外食する回数はどのくらいですか？\', opts:[\'ほぼなし（月1〜2回）\',\'週1回程度\',\'週2〜3回\',\'週4〜5回\',\'ほぼ毎日（週6日以上）\']},\n  {id:\'family\', q:\'Q3. 家族構成は？\', opts:[\'一人暮らし\',\'2人（夫婦・カップル）\',\'子どもあり3〜4人家族\',\'子どもあり5人以上大家族\']},\n  {id:\'purpose\', q:\'Q4. 外食の主な目的は？\', opts:[\'料理が面倒・時短のため\',\'楽しみ・気分転換\',\'仕事の接待・会食\',\'友人・家族との記念日\'],},\n  {id:\'lunch\', q:\'Q5. 平日のランチはどこで食べていますか？\', opts:[\'自炊（弁当・おにぎり）\',\'社員食堂・コンビニ（500円程度）\',\'外食（ランチ1,000円〜）\',\'在宅ワークで自炊\'],},\n  {id:\'delivery\', q:\'Q6. フードデリバリーの利用頻度は？\', opts:[\'ほとんど使わない\',\'月1〜2回（たまに）\',\'週1〜2回\',\'ほぼ毎日使う\']},\n  {id:\'foodDelivery\', q:\'Q7. 食材宅配サービスの利用状況は？\', opts:[\'使っていない\',\'生協・コープを利用\',\'Oisixなどミールキット利用\',\'複数サービス利用中\']},\n  {id:\'motivation\', q:\'Q8. 食費節約への意欲は？\', opts:[\'かなり節約したい\',\'少し節約できればよい\',\'現状でいい\',\'食事の質を落としたくない\']},\n];\n\nlet answers = {}, currentQ = 0;\n\nfunction renderQ() {\n  const q = QUESTIONS[currentQ];\n  document.getElementById(\'qNum\').textContent = currentQ + 1;\n  const pct = Math.round(((currentQ + 1) / QUESTIONS.length) * 100);\n  document.getElementById(\'qPct\').textContent = pct;\n  document.getElementById(\'progressBar\').style.width = pct + \'%\';\n  document.getElementById(\'backBtn\').classList.toggle(\'hidden\', currentQ === 0);\n  document.getElementById(\'questionContainer\').innerHTML = `\n    <h2 class="text-lg font-bold text-gray-800 mb-4">${q.q}</h2>\n    <div class="space-y-2">\n      ${q.opts.map((opt, i) => `\n        <button onclick="selectOpt(${i})"\n          class="w-full text-left px-4 py-3 rounded-xl border-2 text-sm font-medium transition-all\n          ${answers[q.id] === i ? \'border-red-500 bg-red-50 text-red-700\' : \'border-gray-200 bg-gray-50 hover:border-red-300 text-gray-700\'}">\n          ${opt}\n        </button>`).join(\'\')}\n    </div>`;\n}\n\nfunction selectOpt(i) { answers[QUESTIONS[currentQ].id] = i; renderQ(); }\nfunction prevQ() { if (currentQ > 0) { currentQ--; renderQ(); } }\nfunction nextQ() {\n  if (answers[QUESTIONS[currentQ].id] === undefined) { alert(\'選択してください\'); return; }\n  if (currentQ < QUESTIONS.length - 1) { currentQ++; renderQ(); }\n  else showResult();\n}\n\nfunction showResult() {\n  document.getElementById(\'quizArea\').classList.add(\'hidden\');\n  document.getElementById(\'resultArea\').classList.remove(\'hidden\');\n\n  const budget = answers.budget; // 0-5\n  const frequency = answers.frequency; // 0-4\n  const family = answers.family; // 0-3\n  const lunch = answers.lunch; // 0-3\n  const delivery = answers.delivery; // 0-3\n  const motivation = answers.motivation; // 0-3\n\n  // Score: 0=節約型, 100=使いすぎ\n  let score = 0;\n  score += frequency * 20;\n  score += lunch === 2 ? 20 : lunch === 1 ? 10 : 0;\n  score += delivery * 15;\n\n  const budgetAmounts = [15000, 25000, 40000, 65000, 100000, 150000];\n  const monthlyBudget = budgetAmounts[budget];\n  const familyCounts = [1, 2, 3.5, 5];\n  const familySize = familyCounts[family];\n  const perPersonBudget = monthlyBudget / familySize;\n\n  // Reference budget per person\n  const refBudget = 30000; // 1人あたりの目安\n  const budgetRatio = perPersonBudget / refBudget;\n\n  if (budgetRatio > 1.5) score += 30;\n  else if (budgetRatio > 1.2) score += 15;\n\n  score = Math.min(100, Math.max(0, score));\n\n  let emoji, badge, badgeClass, desc;\n  if (score >= 70) {\n    emoji = \'🚨\'; badge = \'外食費が多すぎ！\'; badgeClass = \'bg-red-100 text-red-700\';\n    desc = \'外食・デリバリーへの支出が家計を圧迫している可能性があります。計画的な食費管理が必要です。\';\n  } else if (score >= 40) {\n    emoji = \'⚠️\'; badge = \'やや多め・見直しを\'; badgeClass = \'bg-yellow-100 text-yellow-700\';\n    desc = \'外食費は平均的な範囲ですが、少し改善の余地があります。工夫次第で年間数万円の節約が可能です。\';\n  } else {\n    emoji = \'✅\'; badge = \'節約型・バランス良好\'; badgeClass = \'bg-green-100 text-green-700\';\n    desc = \'食費管理ができています。このまま継続しながら、楽しい外食も大切にしましょう。\';\n  }\n\n  document.getElementById(\'rEmoji\').textContent = emoji;\n  document.getElementById(\'rBadge\').textContent = badge;\n  document.getElementById(\'rBadge\').className = `inline-block px-4 py-1 rounded-full text-sm font-bold mb-2 ${badgeClass}`;\n  document.getElementById(\'rDesc\').textContent'
